#include<bits/stdc++.h>
using namespace std;
int n;
long long tall=-1,shot=1e18;
long long arr[10000005];
int main() {
	cin>>n;
	for (int i=0; i<n; i++) {
		cin>>arr[i];
		if(tall<arr[i]) tall=arr[i];
		if(shot>arr[i]) shot=arr[i];
	}
	for (int i=0; i<n; i++) {
		cout<<tall-arr[i]<<" ";
	}
	cout<<endl;
	for (int i=0; i<n; i++) {
		cout<<arr[i]-shot<<" ";
	}
	return 0;
}
